@use '../../styles/tokens' as *;

.actions-dropdown {
  position: absolute;
  bottom: calc($action-panel-height + $space-2);
  right: $space-2;
  min-width: 220px;
  max-height: 300px;
  overflow-y: auto;
  background-color: $color-surface;
  border: 1px solid $border-100;
  border-radius: $radius-lg;
  box-shadow: $shadow-popover;
  padding: $space-1;
  z-index: 100;
  animation: dropdown-appear $transition-normal ease-out both;
}

.actions-dropdown__item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: $space-4;
  width: 100%;
  padding: $space-2 $space-3;
  background: none;
  border: none;
  border-radius: $radius-md;
  cursor: pointer;
  color: $color-text-primary;
  font-family: $font-family;
  font-size: $font-sm;
  line-height: 1;
  text-align: left;
  transition: background-color $transition-fast ease;

  &:hover,
  &--active {
    background-color: $color-accent;
    color: $color-text-on-accent;

    .actions-dropdown__shortcut .kbd__key {
      background-color: $color-kbd-background-on-accent;
      color: $color-text-on-accent-secondary;
    }
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -2px;
    border-radius: $radius-md;
  }
}

.actions-dropdown__label {
  white-space: nowrap;
}

.actions-dropdown__shortcut {
  display: inline-flex;
  align-items: center;
  flex-shrink: 0;
}

@keyframes dropdown-appear {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(4px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

