  it('clicking action executes and closes', async () => {
    const user = userEvent.setup();
    const { actions, onClose } = renderDropdown();

    await user.click(screen.getByText('Delete'));
    expect(actions[1]!.onClick).toHaveBeenCalledTimes(1);
